import React, { useState, useEffect, useCallback, useRef, Suspense } from 'react';
import { AppState, QuestionData, User, UserAccount, AppTheme, LogoVariant } from './types';
import { fileToBase64 } from './utils/file';
import { playAudio, playBeep, initAudio } from './utils/audio';
import { processQuestionImage, textToSpeech } from './services/geminiService';
import { useScreenRecorder } from './hooks/useScreenRecorder';

import FileUpload from './components/FileUpload';
import QuestionDisplay from './components/QuestionDisplay';
import SpinnerIcon from './components/icons/SpinnerIcon';
import LogoIcon from './components/icons/LogoIcon';
import HomeScreen from './components/HomeScreen';
import LoginPage from './components/LoginPage';
import AdminDashboard from './components/AdminDashboard';
import ArrowLeftIcon from './components/icons/ArrowLeftIcon';
import BackgroundController from './components/BackgroundController';
import SettingsIcon from './components/icons/SettingsIcon';
import SettingsModal from './components/SettingsModal';

// Lazy load components
const Reader = React.lazy(() => import('./components/Reader'));

// Theme Definitions
const THEMES: Record<string, AppTheme> = {
  // --- BASIC / ABSTRACT ---
  PRISM: {
    id: 'PRISM',
    name: 'Geometric Prism',
    category: 'Basic',
    colors: {
      '--color-background': '#1f2937',
      '--color-surface': 'rgba(255, 255, 255, 0.15)',
      '--color-primary': '#2dd4bf',
      '--color-primary-hover': '#14b8a6',
      '--color-secondary': '#fb923c',
      '--color-accent': '#94a3b8',
      '--color-border': 'rgba(45, 212, 191, 0.3)',
      '--color-text-main': '#f1f5f9',
      '--color-text-sub': '#cbd5e1',
      '--color-text-muted': 'rgba(203, 213, 225, 0.5)',
    }
  },
  FLUX: {
    id: 'FLUX',
    name: 'Aurora Flux',
    category: 'Basic',
    colors: {
      '--color-background': '#111827',
      '--color-surface': 'rgba(17, 17, 39, 0.6)',
      '--color-primary': '#22d3ee',
      '--color-primary-hover': '#06b6d4',
      '--color-secondary': '#c026d3',
      '--color-accent': '#818cf8',
      '--color-border': 'rgba(34, 211, 238, 0.3)',
